// Transforma XML de imóveis para o formato Supabase
const xmlData = $input.first().json;
let listings = [];

// Padrão VivaReal/ZAP
if (xmlData.ListingDataFeed?.Listings?.Listing) listings = xmlData.ListingDataFeed.Listings.Listing;
else if (xmlData.imoveis?.imovel) listings = xmlData.imoveis.imovel;
else if (xmlData.rss?.channel?.item) listings = xmlData.rss.channel.item;

if (!Array.isArray(listings)) listings = [listings];

const tenantId = $vars.TENANT_ID; // ID do tenant no Supabase

const imoveis = listings.slice(0, 200).map(item => {
  const preco = parseFloat(
    (item.ListPrice?.[0] || item.preco || item.price || '0').toString().replace(/[^0-9.]/g, '')
  ) || 0;
  const quartos = parseInt(item.BedroomsTotal?.[0] || item.quartos || item.dormitorios || '0') || 0;
  const vagas = parseInt(item.ParkingSpaces?.[0] || item.vagas || item.garagem || '0') || 0;
  const bairro = item.Neighborhood?.[0] || item.bairro || item.neighborhood || item.City?.[0] || '';
  const titulo = item.Title?.[0] || item.titulo || item.title || `Imóvel ${quartos}Q - ${bairro}`;
  const linkSite = item.ViewUrl?.[0] || item.link || item.url || '';
  const descricao = (item.Description?.[0] || item.descricao || item.description || '').toString().substring(0, 500);
  const idImovel = (item.ListingID?.[0] || item.codigo || item.id || linkSite.split('/').pop() || Math.random().toString(36).substring(7)).toString();

  const descLower = descricao.toLowerCase();

  return {
    tenant_id: tenantId,
    id_imovel: idImovel,
    titulo,
    bairro,
    valor: preco,
    quartos,
    vagas,
    link_site: linkSite,
    descricao,
    tem_piscina: descLower.includes('piscina'),
    tem_portaria: descLower.includes('portaria 24') || descLower.includes('segurança 24'),
    aceita_pet: descLower.includes('pet') || descLower.includes('animais permitidos'),
    tem_academia: descLower.includes('academia') || descLower.includes('fitness'),
    tem_lazer: descLower.includes('lazer') || descLower.includes('churrasqueira'),
    disponivel: true,
    ultima_atualizacao: new Date().toISOString()
  };
}).filter(i => i.valor > 0 && i.titulo);

return [{ json: { imoveis, total: imoveis.length } }];

const result = $input.first();
const total = $('Transformar para Supabase').first().json.total;
console.log(`[XML Sync] ${total} imóveis sincronizados com Supabase. Status: ${result.json.$response?.statusCode || 'ok'}`);
return [{ json: { success: true, total, timestamp: new Date().toISOString() } }];
